import { AMT_CONFIRM_BTN_TEXT, AMT_PLACEHOLDER } from '../constants'
import useSplitPaymentStore from '../useSplitPaymentStore'
function TotalAmount() {
    const { setTotalAmount, setShowInstallments } = useSplitPaymentStore((s) => s)
    function handleClick() {
        setTotalAmount(inputVal)
        setShowInstallments()
    }
    return (<div className='flex justify-center gap-4 m-2'>
        <button className='bg-blue-600 text-white border-indigo-500 border-4 rounded-full p-2' onClick={handleClick}>{AMT_CONFIRM_BTN_TEXT}</button>
    </div>)
}

export default TotalAmount
